SELECT total_amount, sale_location
FROM sales
WHERE sale_id = 0;

SELECT SUM(quantity) AS total_sales
FROM sales
WHERE game_id = (SELECT game_id FROM lottery_games WHERE game_name = 'Mega Millions');

SELECT total_sales_amount
FROM game_sales
WHERE game_id = 0;

SELECT prizes_remaining
FROM prizes
WHERE prize_id = 0;

SELECT total_prizes
FROM prizes
WHERE prize_id = 0;

SELECT game_id
FROM game_sales
WHERE total_sales_amount = (
  SELECT MAX(total_sales_amount) 
  FROM game_sales
);

SELECT game_id, SUM(total_sales_amount) AS total_sales
FROM game_sales
GROUP BY game_id;
